import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface ErrorRateTrend {
  time: string;
  errorRate: number;
}

interface ServerData {
  server: {
    uptime: string;
    responseTime: string;
    errorRate: string;
  };
  errorRateTrend: ErrorRateTrend[];
}

export default function Widget() {
  const serverData = response.data as ServerData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#1E1E1E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Server Monitor
            </Typography>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#1D4ED8' }}>
              Uptime: {serverData.server.uptime}
            </Typography>
            <Typography variant="body2" sx={{ color: '#EF4444' }}>
              Response Time: {serverData.server.responseTime}
            </Typography>
            <Typography variant="body2" sx={{ color: '#EF4444' }}>
              Error Rate: {serverData.server.errorRate}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: serverData.errorRateTrend.map((trend) => trend.errorRate),
                  color: '#EF4444',
                  curve: 'linear',
                  label: 'Error Rate',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: serverData.errorRateTrend.map((trend) => trend.time),
                  id: 'time',
                },
              ]}
              yAxis={[{ id: 'errorRate' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="time"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="errorRate"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
